  INSERT INTO public.collection_item_values (id, item_id, field_id, value, is_published, tenant_id, created_at, updated_at, deleted_at) VALUES (gen_random_uuid(), item_id, '2d7e130d-7cb7-45b4-b198-280db5969795'::uuid, 'welcome-new-to-the-centre', false, tid, now(), now(), NULL);
  INSERT INTO public.collection_item_values (id, item_id, field_id, value, is_published, tenant_id, created_at, updated_at, deleted_at) VALUES (gen_random_uuid(), item_id, '0ff536f1-7bdf-4371-8b77-bcda89afd1d2'::uuid, '2026-03-29', false, tid, now(), now(), NULL);
  INSERT INTO public.collection_item_values (id, item_id, field_id, value, is_published, tenant_id, created_at, updated_at, deleted_at) VALUES (gen_random_uuid(), item_id, '4a065863-570f-4ed9-b5d3-ce969f469247'::uuid, 'We are glad you are here. Here is what to expect on your first visit and how to find the prayer hall.', false, tid, now(), now(), NULL);
  INSERT INTO public.collection_item_values (id, item_id, field_id, value, is_published, tenant_id, created_at, updated_at, deleted_at) VALUES (gen_random_uuid(), item_id, 'f4bf761a-8819-430a-8430-44791713644d'::uuid, '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"If you are visiting for the first time, you are welcome to join us for prayer and to ask questions at the office. Please dress modestly and arrive a few minutes before the prayer time so you can find a place comfortably. Jumu‘ah is especially busy — allow extra time for parking."}]}]}', false, tid, now(), now(), NULL);
  INSERT INTO public.collection_item_values (id, item_id, field_id, value, is_published, tenant_id, created_at, updated_at, deleted_at) VALUES (gen_random_uuid(), item_id, '776750d4-6ebe-4cf7-b520-1464ab695b77'::uuid, 'true', false, tid, now(), now(), NULL);
