  INSERT INTO public.collection_item_values (id, item_id, field_id, value, is_published, tenant_id, created_at, updated_at, deleted_at) VALUES (gen_random_uuid(), item_id, '2d7e130d-7cb7-45b4-b198-280db5969795'::uuid, 'friday-sermon-prayer', false, tid, now(), now(), NULL);
  INSERT INTO public.collection_item_values (id, item_id, field_id, value, is_published, tenant_id, created_at, updated_at, deleted_at) VALUES (gen_random_uuid(), item_id, '0ff536f1-7bdf-4371-8b77-bcda89afd1d2'::uuid, '2026-03-29', false, tid, now(), now(), NULL);
  INSERT INTO public.collection_item_values (id, item_id, field_id, value, is_published, tenant_id, created_at, updated_at, deleted_at) VALUES (gen_random_uuid(), item_id, '4a065863-570f-4ed9-b5d3-ce969f469247'::uuid, 'Khutbah begins shortly before the prayer; doors open earlier for quiet reflection.', false, tid, now(), now(), NULL);
  INSERT INTO public.collection_item_values (id, item_id, field_id, value, is_published, tenant_id, created_at, updated_at, deleted_at) VALUES (gen_random_uuid(), item_id, 'f4bf761a-8819-430a-8430-44791713644d'::uuid, '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Jumu‘ah is a special gathering for the community. The khutbah usually begins around fifteen to twenty minutes before the adhan for Zuhr, but times can vary seasonally — check the weekly timetable. Visitors are welcome; please follow steward directions during busy periods."}]}]}', false, tid, now(), now(), NULL);
  INSERT INTO public.collection_item_values (id, item_id, field_id, value, is_published, tenant_id, created_at, updated_at, deleted_at) VALUES (gen_random_uuid(), item_id, '776750d4-6ebe-4cf7-b520-1464ab695b77'::uuid, 'true', false, tid, now(), now(), NULL);
