  INSERT INTO public.collection_item_values (id, item_id, field_id, value, is_published, tenant_id, created_at, updated_at, deleted_at) VALUES (gen_random_uuid(), item_id, 'f1b5777b-a3d5-440d-a35b-819a804e2978'::uuid, '2026-03-29T13:15:16.620Z', false, tid, now(), now(), NULL);
  INSERT INTO public.collection_item_values (id, item_id, field_id, value, is_published, tenant_id, created_at, updated_at, deleted_at) VALUES (gen_random_uuid(), item_id, '570caa53-5753-4f38-859c-1c655629bde9'::uuid, '2026-03-29T13:15:16.620Z', false, tid, now(), now(), NULL);
  INSERT INTO public.collection_item_values (id, item_id, field_id, value, is_published, tenant_id, created_at, updated_at, deleted_at) VALUES (gen_random_uuid(), item_id, 'd21f751d-9c50-4d51-9b2f-4b45c2ff3895'::uuid, 'Ramadan and community iftar', false, tid, now(), now(), NULL);
  INSERT INTO public.collection_item_values (id, item_id, field_id, value, is_published, tenant_id, created_at, updated_at, deleted_at) VALUES (gen_random_uuid(), item_id, '2d7e130d-7cb7-45b4-b198-280db5969795'::uuid, 'ramadan-community-iftar', false, tid, now(), now(), NULL);
  INSERT INTO public.collection_item_values (id, item_id, field_id, value, is_published, tenant_id, created_at, updated_at, deleted_at) VALUES (gen_random_uuid(), item_id, '0ff536f1-7bdf-4371-8b77-bcda89afd1d2'::uuid, '2026-03-29', false, tid, now(), now(), NULL);
  INSERT INTO public.collection_item_values (id, item_id, field_id, value, is_published, tenant_id, created_at, updated_at, deleted_at) VALUES (gen_random_uuid(), item_id, '4a065863-570f-4ed9-b5d3-ce969f469247'::uuid, 'During Ramadan we share updated timetables, taraweeh arrangements, and charity appeals.', false, tid, now(), now(), NULL);
  INSERT INTO public.collection_item_values (id, item_id, field_id, value, is_published, tenant_id, created_at, updated_at, deleted_at) VALUES (gen_random_uuid(), item_id, 'f4bf761a-8819-430a-8430-44791713644d'::uuid, '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Ramadan is a blessed month for fasting, prayer, and charity. We publish a daily timetable for imsak, fajr, maghrib, and taraweeh. Community iftars may be organised on selected dates — registration or tickets may be required when capacity is limited. Zakat and sadaqah can usually be given at the office or online where available."}]}]}', false, tid, now(), now(), NULL);
  INSERT INTO public.collection_item_values (id, item_id, field_id, value, is_published, tenant_id, created_at, updated_at, deleted_at) VALUES (gen_random_uuid(), item_id, '776750d4-6ebe-4cf7-b520-1464ab695b77'::uuid, 'false', false, tid, now(), now(), NULL);
