  INSERT INTO public.collection_item_values (id, item_id, field_id, value, is_published, tenant_id, created_at, updated_at, deleted_at) VALUES (gen_random_uuid(), item_id, 'c81b849e-720c-4963-8cbf-7903045442ec'::uuid, 'visitor-guide', false, tid, now(), now(), NULL);
  INSERT INTO public.collection_item_values (id, item_id, field_id, value, is_published, tenant_id, created_at, updated_at, deleted_at) VALUES (gen_random_uuid(), item_id, '99d5570e-e117-417f-92da-5b5c9cf8549f'::uuid, '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"The centre is open around the five daily prayers and for scheduled classes. Office hours may differ — call or email before visiting for administrative matters."}]}]}', false, tid, now(), now(), NULL);
  INSERT INTO public.collection_item_values (id, item_id, field_id, value, is_published, tenant_id, created_at, updated_at, deleted_at) VALUES (gen_random_uuid(), item_id, '80238458-5063-48de-af81-600b2d5f4158'::uuid, '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Please remove footwear in the prayer hall area, keep phones silent, and avoid eating or drinking in the musalla. Non-Muslim visitors are welcome to observe quietly from designated areas when offered."}]}]}', false, tid, now(), now(), NULL);
  INSERT INTO public.collection_item_values (id, item_id, field_id, value, is_published, tenant_id, created_at, updated_at, deleted_at) VALUES (gen_random_uuid(), item_id, '21bf75b3-5fe4-4c2f-a187-df20f7a9e457'::uuid, '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Limited on-site parking; respect residents when street parking. Blue-badge bays are available near the main entrance where marked. Cycling racks are provided at the side gate."}]}]}', false, tid, now(), now(), NULL);
